#include <sycl/sycl.hpp>
#include <cstdio>
#include <vector>

int main() {
    sycl::queue q(sycl::default_selector_v);
    std::vector<int> data = {1, 2, 3};
    sycl::buffer<int, 1> buf(data);
    q.submit([&](sycl::handler& h) {
        sycl::accessor acc(buf, h, sycl::read_write);
        h.parallel_for(sycl::range<1>(3), [=](sycl::id<1> idx) {
            acc[idx[0]] = acc[idx[0]] + 1;
        });
    });
    q.wait();
    {
        sycl::host_accessor acc(buf, sycl::read_only);
        printf("%d %d %d\n", acc[0], acc[1], acc[2]);
    }
    return 0;
}
```

**Explanation:** **accessor** in the kernel allows each work item to read/write by index. **idx[0]** is 0, 1, or 2. After **wait()**, **host_accessor** reads the updated data.

