Single task reduces to one value.

```
#include <sycl/sycl.hpp>
#include <cstdio>
#include <vector>

int main() {
    sycl::queue q(sycl::default_selector_v);
    std::vector<int> in_data = {10, 20, 30, 40};
    std::vector<int> out_data = {0};
    sycl::buffer<int, 1> buf_in(in_data);
    sycl::buffer<int, 1> buf_out(out_data);
    q.submit([&](sycl::handler& h) {
        sycl::accessor acc_in(buf_in, h, sycl::read_only);
        sycl::accessor acc_out(buf_out, h, sycl::write_only);
        h.single_task([=]() {
            int sum = acc_in[0] + acc_in[1] + acc_in[2] + acc_in[3];
            acc_out[0] = sum;
        });
    });
    q.wait();
    {
        sycl::host_accessor acc(buf_out, sycl::read_only);
        printf("%d\n", acc[0]);
    }
    return 0;
}
```

**Explanation:** **read_only** and **write_only** accessors express access mode. The single_task reads all four elements and writes the sum to the output buffer. **host_accessor** retrieves the result.

